const wh = $('Webhook').first().json;
const input = wh.body || wh;

const GEMINI_KEYS = [
  { name: 'eilinaire',       key: $env.EILINAIRE_GOOGLE_API_KEY },
  { name: 'jooshdathumlong', key: $env.JOOSHDATHUMLONG_GOOGLE_API_KEY },
  { name: 'mahittisak',      key: $env.MAHITTISAK_GOOGLE_API_KEY },
  { name: 'sunsetsol',       key: $env.SUNSETSOL_GOOGLE_API_KEY },
  { name: 'rlie',            key: $env.RLIE_GOOGLE_API_KEY },
  { name: 'peabantid',       key: $env.PEABANTID_GOOGLE_API_KEY },
].filter(k => k.key);

// Tiered model selection (Blueprint 1.3)
const TIER_MODELS = {
  0: 'gemini-2.0-flash',        // Full capability
  1: 'gemini-2.0-flash',        // Cost alert — same model, thinking tasks routed elsewhere
  2: 'gemini-2.0-flash-lite',   // Cost limit
  3: 'ollama/llama3.1',         // Emergency — local only
};

const MATRIX = {
  'CREATIVE':  { primary: 'gemini-2.0-flash', fallback: 'ollama/llama3.1' },
  'PERSONAL':  { primary: 'gemini-2.0-flash', fallback: 'gemini-2.0-flash-lite' },
  'JOB':       { primary: 'gemini-2.0-flash', fallback: 'gemini-2.0-flash-lite' },
  'default':   { primary: 'gemini-2.0-flash', fallback: 'gemini-2.0-flash-lite' }
};
const AGENT_MAP = { JOB: 'jeff', PERSONAL: 'eilinaire', CREATIVE: 'ego_era' };

const pillar    = (input.pillar || 'default').toUpperCase();
const reduced   = input.reduced_mode === true;
const throttled = {};

for (const row of $('Check Rate Limits').all()) {
  if (row.json.is_throttled) throttled[row.json.provider] = true;
}

// Determine tier from throttled providers
const geminiThrottled = throttled['gemini-2.0-flash'];
const flashLiteThrottled = throttled['gemini-2.0-flash-lite'];
let tier = 0;
if (geminiThrottled && flashLiteThrottled) tier = 3;
else if (geminiThrottled) tier = 2;

const matrixKey = Object.keys(MATRIX).find(k => pillar.startsWith(k)) || 'default';
let selectedModel = reduced ? 'gemini-2.0-flash-lite' : TIER_MODELS[tier] || MATRIX[matrixKey].primary;
// Final fallback to Ollama if selected model throttled
if (throttled[selectedModel]) selectedModel = 'ollama/llama3.1';

const keyIndex = Math.floor(Date.now() / 60000) % GEMINI_KEYS.length;
const geminiKey = GEMINI_KEYS[keyIndex] || {};
const topPillar = pillar.split('.')[0];
const assignedAgent = AGENT_MAP[topPillar] || 'jeff';

return [{ json: {
  assigned_agent: assignedAgent,
  selected_model: selectedModel,
  tier,
  pillar,
  message: input.message || '',
  user_id: input.user_id || '',
  routed_at: new Date().toISOString()
}}];

